function formatTime(sec){const h=Math.floor(sec/3600),m=Math.floor((sec%3600)/60),s=sec%60;return `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`}
function examQuestionStatus(idx){if(mockState.status[idx]==='review')return'review';if(mockState.answers[idx]!=null)return'answered';if(mockState.visited[idx])return'visited';return'unseen'}
function examCounts(){const counts={unseen:0,visited:0,answered:0,review:0};mockState.questions.forEach((_,idx)=>{counts[examQuestionStatus(idx)]++});return counts}
function formatExamDuration(mins){const h=Math.floor(mins/60),m=mins%60;return`${h} Hour${h!==1?'s':''}${m?` ${m} Minute${m!==1?'s':''}`:''}`}
function currentExamLanguages(){const raw=(document.body.dataset.examLanguages||'hindi,english').split(',').map(x=>x.trim().toLowerCase()).filter(Boolean);return raw.length?raw:['hindi','english']}
function currentMockLang(){return mockState.config.language==='english'?'english':'hindi'}
function mockExamTitle(){return document.body.dataset.examTitle||'Indian Banking Mock Test'}
function mockSetName(){return document.body.dataset.examSetName||(mockState.config.category==='All'?'Mixed Banking Set':mockState.config.category)}
function mockExamReference(q){return q.ref||''}
function mockTextEn(q){
 const text=q.q||'';
 if(text.includes('किस संस्था को भारत का केंद्रीय बैंक'))return'Which institution is called the central bank of India?';
 if(text.includes('CASA'))return'What is the full form of CASA?';
 if(text.includes('KYC'))return'What is the main purpose of KYC?';
 if(text.includes('NEFT'))return'NEFT fund transfer is settled on which basis?';
 if(text.includes('IMPS'))return'What is the key feature of IMPS?';
 if(text.includes('UPI PIN'))return'What is a UPI PIN used for?';
 if(text.includes('NPA'))return'When is a loan/account classified as NPA?';
 if(text.includes('MICR'))return'What is the use of MICR code on a cheque?';
 if(text.includes('Demand Draft'))return'What type of banking instrument is a Demand Draft?';
 if(text.includes('Nominee'))return'What is the role of a nominee in a bank account?';
 if(text.includes('₹10,000'))return'What will be the simple interest on ₹10,000 at 10% per annum for 2 years?';
 if(text.includes('EMI ₹8,000'))return'If EMI is ₹8,000 and monthly income is ₹40,000, what is the EMI-to-income ratio?';
 if(text.includes('₹50,000 का 12%'))return'What is 12% of ₹50,000?';
 if(text.includes('3 साल')&&text.includes('double'))return'If an amount doubles in 3 years at simple interest, what is the annual rate?';
 if(text.includes('₹2,000 का 15%'))return'What is 15% discount on ₹2,000?';
 if(text.includes('श्रृंखला पूरी करें'))return text.replace('श्रृंखला पूरी करें','Complete the series');
 if(text.includes('यदि BANK को CBNL'))return'If BANK is coded as CBNL, how will LOAN be coded?';
 if(text.includes('Odd one out'))return'Choose the odd one out: Saving, Current, Fixed Deposit, Keyboard';
 if(text.includes('A, B का भाई'))return'A is brother of B and B is sister of C. What is A’s relation with C?';
 if(text.includes('अगर आज Monday'))return'If today is Monday, what day will it be after 10 days?';
 if(text.includes('जमा किए')&&text.includes('simple interest'))return text.replace('ने','deposited').replace('में','in').replace('जमा किए।','').replace('वर्ष का interest कितना होगा?','years? What will be the simple interest?');
 if(q.cat==='English')return text;
 return'English version: Original banking exam pattern practice question based on the Hindi question above.';
}
function mockTextHi(q){
 const text=q.q||'';
 if(/[\u0900-\u097F]/.test(text))return text;
 if(text.includes('Choose the correct spelling'))return'सही spelling चुनें।';
 if(text.includes('Opposite of “Credit”'))return'Banking context में “Credit” का सामान्य opposite क्या है?';
 if(text.includes('Fill in the blank'))return'खाली स्थान भरें: Please ____ your KYC documents.';
 if(text.includes('Synonym of “verify”'))return'“verify” का synonym चुनें।';
 if(text.includes('Correct phrase'))return'सही phrase चुनें।';
 return'हिंदी रूप: यह banking exam pattern पर आधारित original/rephrased practice question है।';
}
