 if(!mockState.questions.length)return;clearInterval(mockState.timer);mockState.started=false;
 let right=0,wrong=0,skip=0;const review=mockState.questions.map((x,idx)=>{const given=mockState.answers[idx];if(given==null)skip++;else if(given===x.ans)right++;else wrong++;const cls=given===x.ans?'correct':(given==null?'skipped':'wrong');return `<div class="review-card"><h3>Q${idx+1}. ${mockQuestionHtml(x)}</h3><p class="review-answer ${cls}">Your Answer: ${given==null?'Not Attempted':mockOptionLabel(x.opts[given])}</p><p class="review-answer correct">Correct Answer: ${mockOptionLabel(x.opts[x.ans])}</p>${mockExplanationHtml(x)}</div>`}).join('');
